public class CreateOrderValidator : AbstractValidator<CreateOrderDto>
{
    public CreateOrderValidator(IProductRepository productRepo)
    {
        RuleFor(x => x.CustomerId)
            .NotEmpty()
            .GreaterThan(0).WithMessage("CustomerId phải lớn hơn 0");

        RuleFor(x => x.ProductId)
            .MustAsync(async (id, ct) => await productRepo.ExistsAsync(id, ct))
            .WithMessage("Sản phẩm {PropertyValue} không tồn tại");

        RuleFor(x => x.Quantity)
            .GreaterThan(0)
            .LessThanOrEqualTo(100).WithMessage("Số lượng tối đa là 100");

        // Conditional: chỉ validate coupon khi có coupon
        When(x => !string.IsNullOrEmpty(x.CouponCode), () =>
        {
            RuleFor(x => x.CouponCode!)
                .Length(6, 20)
                .MustAsync(async (code, ct) =>
                    await productRepo.IsCouponValidAsync(code, ct))
                .WithMessage("Mã giảm giá '{PropertyValue}' không hợp lệ");
        });
    }
}

